import (
	"html/template"
	"net/http"
)

// HandleProductSearch processes search queries and displays results safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Use html/template for safe HTML generation. 
	// This automatically escapes the keyword to prevent Cross-Site Scripting (XSS).
	const searchResultsTmpl = `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`

	t, err := template.New("search").Parse(searchResultsTmpl)
	if err != nil {
		// If template parsing fails, return a 500 error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the keyword. 
	// The template engine handles the necessary escaping for the provided context.
	err = t.Execute(w, keyword)
	if err != nil {
		// In a production environment, you would log this error.
		return
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	// Example usage: http.ListenAndServe(":8080", nil)
}

