package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes search requests and displays results with analytics logging.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the 'keyword' query parameter from the URL
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a production environment, this would typically involve sending data to 
	// an analytics engine (like GA, Mixpanel, or an internal database).
	// Here we simulate it by logging the search event.
	logAnalytics(r, keyword)

	// 3. Set the Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// 5. Write the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Search performed at: %s</p>
</body>
</html>`, safeKeyword, time.Now().Format(time.RFC1123))
}

