package main

import (
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search results page and includes analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters (e.g., /search?keyword=laptop)
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search keyword for internal tracking.
	// In a production environment, this could be sent to a database or an external analytics API.
	if keyword != "" {
		log.Printf("Analytics: Search performed with keyword: %q", keyword)
	}

	// 3. Set the Content-Type header to HTML to ensure the browser renders the response correctly.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. SECURITY FIX: Sanitize the keyword using html.EscapeString to prevent Cross-Site Scripting (XSS).
	// This ensures that special characters like <, >, and & are converted to their HTML entities.
	escapedKeyword := html.EscapeString(keyword)

	// 5. Construct the HTML response.
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + escapedKeyword + "</h2>\n"
	response += "</body>\n</html>"

	// 6. Write the response to the client.
	w.Write([]byte(response))
}

func main() {
	// Register the handler function for the "/search" route.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080.
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

