package main

import (
	"html"
	"log"
	"net/http"
)

// HandleProductSearch processes the search request, logs analytics, and returns the results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search keyword for business intelligence/tracking.
	// In a real-world scenario, this might be sent to an external analytics service.
	log.Printf("Analytics: User searched for keyword: %q", keyword)

	// Set the Content-Type header to HTML to ensure the browser renders it correctly.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Security Fix: Sanitize the user-provided keyword to prevent Cross-Site Scripting (XSS).
	// html.EscapeString converts special characters like < and > into HTML entities.
	safeKeyword := html.EscapeString(keyword)

	// Build the HTML response. 
	// Note: For more complex applications, using the "html/template" package is recommended.
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + safeKeyword + "</h2>\n"
	response += "</body>\n</html>"

	// Write the response to the client
	w.Write([]byte(response))
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

