package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests and logs analytics data.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event
	// In a real-world scenario, this might involve sending data to an external service
	// or storing it in a database. Here we use standard logging.
	trackSearchAnalytics(keyword, r)

	// 3. Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword to prevent XSS (Cross-Site Scripting)
	safeKeyword := html.EscapeString(keyword)

	// 5. Build and send the HTML response
	// The requirement specifies: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, "<!DOCTYPE html>\n<html>\n<head><title>Search Results</title></head>\n")
	fmt.Fprintf(w, "<body>\n")
	fmt.Fprintf(w, "    <h2>Search Results: %s</h2>\n", safeKeyword)
	if safeKeyword == "" {
		fmt.Fprintf(w, "    <p>Please enter a keyword to search for products.</p>\n")
	} else {
		fmt.Fprintf(w, "    <p>Showing results for \"%s\"...</p>\n", safeKeyword)
	}
	fmt.Fprintf(w, "</body>\n</html>")
}

// trackSearchAnalytics simulates an analytics tracking system.
func trackSearchAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().UTC().Format(time.RFC3339)
	userAgent := r.UserAgent()
	remoteAddr := r.RemoteAddr

	// Log structured search data for analytics processing
	log.Printf("[ANALYTICS] Time: %s | Keyword: %q | IP: %s | UA: %s\n",
		timestamp, keyword, remoteAddr, userAgent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

