// HandleProductSearch processes the search request and displays results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// --- Analytics Support ---
	// In a production environment, this would send data to an analytics engine.
	// For this implementation, we log the search event with a timestamp.
	log.Printf("[Analytics] Search Request - Keyword: %q, RemoteAddr: %s, Time: %s", 
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
    <style>
        body { font-family: sans-serif; padding: 20px; }
        .analytics-status { color: #666; font-size: 0.8em; margin-top: 20px; border-top: 1px solid #eee; }
    </style>
</head>
<body>
    <h2>Search Results: [%s]</h2>

    <div class="results-placeholder">
        <p>Showing items matching your search criteria.</p>
    </div>

    <footer class="analytics-status">
        <p>Analytics: Search event recorded.</p>
    </footer>

    <!-- Mock Analytics Script -->
    <script>
        (function() {
            console.log("Analytics: Tracking keyword search: " + JSON.stringify(%q));
        })();
    </script>
</body>
</html>`, safeKeyword, keyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define server port
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)

	// Start the server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Could not start server: %s\n", err)
	}
}

