// It extracts the keyword, logs it for analytics, and renders the results safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics support: Log the search keyword for internal tracking
	// In a production environment, this could also be sent to an external analytics service.
	log.Printf("Analytics: Product search performed with keyword: %s", keyword)

	// 3. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

