import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics represents a simple structure for tracking search data.
type SearchAnalytics struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
}

// HandleProductSearch processes search requests and displays results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event
	// In a real-world scenario, this might be sent to a database or a message queue.
	analytics := SearchAnalytics{
		Keyword:   keyword,
		Timestamp: time.Now(),
		UserAgent: r.UserAgent(),
	}
	log.Printf("Analytics Log: Keyword='%s' Time='%s' UA='%s'", 
		analytics.Keyword, 
		analytics.Timestamp.Format(time.RFC3339), 
		analytics.UserAgent,
	)

	// 3. Set Response Header
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Security: Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// 5. Generate and write the HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Search results logic would follow here -->
    <p>Analytics tracked for this request.</p>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

