</body>
</html>`, safeKeyword, time.Now().Format(time.RFC1123))
}

// logSearchAnalytics simulates an analytics tracking system.
func logSearchAnalytics(keyword, ip, ua string) {
	timestamp := time.Now().Format(time.RFC3339)
	log.Printf("[ANALYTICS] Timestamp: %s | Keyword: %q | IP: %s | UserAgent: %s\n", 
		timestamp, keyword, ip, ua)
}

