package main

import (
	"html/template"
	"log"
	"net/http"
)

// Pre-parsing the template at package level for performance and safety.
// html/template automatically handles context-aware escaping to prevent XSS.
var searchTemplate = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.}}</h2>
</body>
</html>`))

// HandleProductSearch processes the search request, logs analytics, and renders results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// Logging the keyword allows for basic search behavior tracking.
	// In a production environment, this could be sent to a dedicated analytics service.
	log.Printf("Analytics: Search keyword received: %q", keyword)

	// 3. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Execute the template safely
	// The template engine will escape the keyword to prevent Cross-Site Scripting (XSS).
	err := searchTemplate.Execute(w, keyword)
	if err != nil {
		log.Printf("Error executing template: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the web server
	addr := ":8080"
	log.Printf("Server starting on %s", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

