func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters.
	// r.URL.Query().Get handles URL decoding automatically.
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML to ensure the browser interprets it correctly.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the user-provided keyword.
	// html/template will automatically escape any special characters in 'keyword'
