package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes the search request, provides basic analytics,
// and returns an HTML response displaying the search keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the 'keyword' from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a production environment, this might involve pushing to a message queue or database.
	// For this implementation, we log the search event with a timestamp for analytics tracking.
	log.Printf("[Analytics] Search Keyword: %q | RemoteAddr: %s | Time: %s", 
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Set Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize user input to prevent Cross-Site Scripting (XSS)
	// Even though it's a simple display, escaping is a professional standard.
	safeKeyword := html.EscapeString(keyword)

	// 5. Write the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, `<!DOCTYPE html>
<html>
<head>
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler function for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Define server port
	port := ":8080"
	log.Printf("Starting server on %s...", port)

	// Start the HTTP server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

