package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests and displays results.
// It extracts the 'keyword' query parameter and renders it in an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event
	// In a real-world scenario, this might send data to an external service.
	log.Printf("[Analytics] Search performed - Keyword: %q, RemoteAddr: %s, Time: %s",
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// 3. Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// 5. Generate the HTML response
	// Using fmt.Fprintf to write the HTML structure directly to the ResponseWriter
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Analytics recorded at: %s</p>
</body>
</html>`, safeKeyword, time.Now().Format(time.Kitchen))
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define server port
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)

	// Start the server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

