import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// AnalyticsEvent represents a search event for tracking purposes
type AnalyticsEvent struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	RemoteIP  string    `json:"remote_ip"`
}

// HandleProductSearch processes product search requests and displays results.
// It extracts the 'keyword' from the query parameters, logs the search for analytics,
// and returns an HTML response containing the keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event
	// In a production environment, this might be sent to a time-series database or a message queue.
	event := AnalyticsEvent{
		Keyword:   keyword,
		Timestamp: time.Now(),
		RemoteIP:  r.RemoteAddr,
	}
	log.Printf("Analytics Log: Keyword='%s' IP='%s' Time='%s'\n", event.Keyword, event.RemoteIP, event.Timestamp.Format(time.RFC3339))

	// 3. Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// 5. Write the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Search results would be rendered here -->
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define server parameters
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)

	// Start the server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

