package main

import (
	"html"
	"net/http"
)

// HandleProductSearch handles the product search results page.
// It extracts the 'keyword' query parameter and displays it safely in an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML to ensure the browser renders it correctly
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// SECURITY FIX: Escape the keyword to prevent Cross-Site Scripting (XSS).
	// html.EscapeString converts special characters like "<" to "&lt;", 
	// ensuring user input is treated as text rather than executable code.
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// The keyword is displayed within the <h2> tag as requested.
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + escapedKeyword + "</h2>\n"
	response += "</body>\n</html>"

	// Write the response back to the client
	w.Write([]byte(response))
}

func main() {
	// Register the handler for the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server on port 8080
	// Example URL: http://localhost:8080/search?keyword=Golang
	http.ListenAndServe(":8080", nil)
}

