package main

import (
	"html/template"
	"net/http"
)

// HandleProductSearch handles the product search results page securely.
// It extracts the 'keyword' query parameter and displays it using auto-escaping
// to prevent Cross-Site Scripting (XSS) vulnerabilities.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: In a production environment, you would log the keyword 
	// or send it to an analytics service here for tracking search trends.

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template. 
	// Using html/template is the professional standard in Go for preventing XSS.
	// The {{.}} action will automatically escape the keyword based on its context.
	const tplSource = `<!DOCTYPE html>
<html>
<head>
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.}}</h2>
</body>
</html>`

	// Parse the template
	tmpl, err := template.New("search").Parse(tplSource)
	if err != nil {
		// If template parsing fails, return an internal server error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the keyword. 
	// The template engine ensures the keyword is rendered safely as text.
	if err := tmpl.Execute(w, keyword); err != nil {
		// Handle potential execution errors
		return
	}
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	http.ListenAndServe(":8080", nil)
}

