// HandleProductSearch handles product search requests and displays results.
// It extracts the 'keyword' from the query parameters and renders it in an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 3. Escape the keyword to prevent Cross-Site Scripting (XSS)
	// Even though we are using fmt.Fprintf, we manually escape for safety within the HTML context.
	safeKeyword := html.EscapeString(keyword)

	// 4. Construct and write the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <header>
        <h2>Search Results: %s</h2>
    </header>
    <main>
        <!-- Analytics support and product listings would be integrated here -->
        <p>Showing results for your query.</p>
    </main>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

