	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests and provides basic analytics.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event with timestamp
	// In a real-world scenario, this might be sent to a database or a message queue.
	log.Printf("[Analytics] Search Keyword: %q | Time: %s | RemoteAddr: %s", 
		keyword, time.Now().Format(time.RFC3339), r.RemoteAddr)

	// 3. Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword for safe HTML output (XSS prevention)
	safeKeyword := html.EscapeString(keyword)

	// 5. Construct the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	fmt.Fprintf(w, "<!DOCTYPE html>\n<html>\n<head>\n<title>Search Results</title>\n</head>\n<body>\n")
	fmt.Fprintf(w, "    <h2>Search Results: %s</h2>\n", safeKeyword)

	// Optional: Add a message if keyword is empty
	if keyword == "" {
		fmt.Fprint(w, "    <p>Please enter a keyword to search for products.</p>\n")
	} else {
		fmt.Fprintf(w, "    <p>Showing products matching your search for \"%s\".</p>\n", safeKeyword)
	}

	fmt.Fprintf(w, "</body>\n</html>")
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)

	server := &http.Server{
		Addr:         port,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	if err := server.ListenAndServe(); err != nil {
		log.Fatal(err)
	}
}

