import (
	"html/template"
	"log"
	"net/http"
)

// Pre-parsing the template at the package level is more efficient than parsing it 
// inside the handler for every request. html/template automatically escapes 
// the data passed to it, preventing XSS vulnerabilities.
var searchTemplate = template.Must(template.New("searchResults").Parse(`<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
</body>
</html>`))

// HandleProductSearch handles the product search results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters.
	// r.URL.Query().Get returns an empty string if the parameter is missing.
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support:
	// In a professional application, this would log to a database or an external 
	// analytics service. Here we use standard logging to track user searches.
	if keyword != "" {
		log.Printf("Analytics: Search performed with keyword: %q", keyword)
	}

	// 3. Set the Content-Type header to HTML with UTF-8 encoding.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Prepare data for the template.
	data := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	// 5. Execute the template and write the response.
	// The template engine handles the necessary escaping for the 'Keyword' field.
	if err := searchTemplate.Execute(w, data); err != nil {
		// If an error occurs during execution, log it for server-side debugging.
		log.Printf("Error executing template: %v", err)
		// Note: Header might have already been sent, but we attempt to signal an error.
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler for the search route.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server.
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=example", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

