package main

import (
	"html/template"
	"log"
	"net/http"
)

// Define the HTML template. Using the html/template package is the professional 
// standard in Go for generating HTML as it provides automatic contextual escaping, 
// which is essential for preventing Cross-Site Scripting (XSS) vulnerabilities.
var searchTemplate = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`))

// HandleProductSearch handles the product search results page and includes analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from the URL query parameter 'keyword'.
	// r.URL.Query().Get() returns an empty string if the parameter is missing.
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search keyword for tracking and analysis.
	// In a production environment, this might be sent to a dedicated analytics service.
	log.Printf("Analytics: Product search keyword received: %s", keyword)

	// Set the Content-Type header to ensure the browser interprets the response as UTF-8 HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the keyword. The template engine will automatically 
	// escape any special characters in the keyword (e.g., <, >, &) to ensure 
	// the output is safe for the HTML context.
	if err := searchTemplate.Execute(w, keyword); err != nil {
		// If template execution fails, return a 500 Internal Server Error.
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

func main() {
	// Register the search results handler.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080.
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

