package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics represents the structure for tracking search events.
type SearchAnalytics struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	RemoteIP  string    `json:"remote_ip"`
}

// trackSearchEvent simulates sending data to an analytics service.
func trackSearchEvent(keyword string, r *http.Request) {
	analytics := SearchAnalytics{
		Keyword:   keyword,
		Timestamp: time.Now().UTC(),
		RemoteIP:  r.RemoteAddr,
	}
	// In a production environment, this would typically send data to a 
	// time-series database, a message broker like Kafka, or a logging service.
	log.Printf("[Analytics] Search Triggered - Keyword: %q, Time: %s, IP: %s", 
		analytics.Keyword, 
		analytics.Timestamp.Format(time.RFC3339), 
		analytics.RemoteIP,
	)
}

// HandleProductSearch processes the search request and returns an HTML results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Trigger analytics support
	trackSearchEvent(keyword, r)

	// 3. Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the input to prevent Cross-Site Scripting (XSS)
	// Even though it's a simple display, escaping is a security best practice.
	safeKeyword := html.EscapeString(keyword)

	// 5. Write the HTML response
	// We use fmt.Fprintf to write the formatted string directly to the ResponseWriter.
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
    <style>
        body { font-family: sans-serif; margin: 40px; line-height: 1.6; }
        .search-header { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }
    </style>
</head>
<body>
    <div class="search-header">
        <h2>Search Results: %s</h2>
    </div>
    <main>
        <p>Showing products matching your search criteria.</p>
        <!-- Product listing logic would go here -->
    </main>
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define server parameters
	port := ":8080"
	fmt.Printf("Starting server on %s...\n", port)
	fmt.Printf("Try accessing: http://localhost%s/search?keyword=Golang\n", port)

	// Start the HTTP server
	server := &http.Server{
		Addr:         port,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

