// and renders an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support
	// In a production environment, this might involve sending data to a 
	// message queue or an external tracking API. Here we log the search event.
	log.Printf("[Analytics] Search Event: keyword=%q, timestamp=%s, user_agent=%q",
