		time.Now().Format(time.RFC3339),
		r.UserAgent(),
	)

	// 3. Set the Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Define and parse the HTML template
	// We use html/template to ensure the keyword is properly escaped, 
	// protecting the application against Cross-Site Scripting (XSS) attacks.
	const tpl = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: sans-serif; padding: 20px; line-height: 1.6; }
        .search-header { color: #333; border-bottom: 1px solid #eee; padding-bottom: 10px; }
    </style>
</head>
<body>
    <div class="search-header">
        <h2>Search Results: {{.Keyword}}</h2>
    </div>
    <main>
        {{if .Keyword}}
            <p>Showing results for "<strong>{{.Keyword}}</strong>".</p>
            <!-- Product list would be populated here -->
            <ul>
                <li>Sample Product 1 (Related to {{.Keyword}})</li>
                <li>Sample Product 2 (Related to {{.Keyword}})</li>
            </ul>
        {{else}}
            <p>Please enter a search keyword.</p>
        {{end}}
    </main>
</body>
</html>`

	t, err := template.New("searchPage").Parse(tpl)
	if err != nil {
		log.Printf("Template parsing error: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// 5. Execute the template with the provided keyword
	data := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	if err := t.Execute(w, data); err != nil {
		log.Printf("Template execution error: %v", err)
		// Header already sent by this point if Execute fails mid-stream, 
		// but standard practice is to handle the error.
	}
}

func main() {
	// Route registration
	http.HandleFunc("/search", HandleProductSearch)

