// We pre-parse the template to ensure efficiency and safety.
// Using html/template is the professional standard in Go for generating HTML
// because it provides context-aware escaping, which prevents Cross-Site Scripting (XSS).
var searchTmpl = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Product Search Results</title>
</head>
<body>
