</body>
</html>`))

// HandleProductSearch processes the product search request.
// It extracts the 'keyword' from the URL query parameters and renders it safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters (e.g., ?keyword=phone)
	keyword := r.URL.Query().Get("keyword")

	// Analytics support:
	// In a production environment, the keyword would be logged or sent to 
	// an analytics service here before rendering the response.

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the user-provided keyword.
	// The template engine automatically escapes the keyword to prevent XSS attacks.
	if err := searchTmpl.Execute(w, keyword); err != nil {
		// If rendering fails, return an internal server error.
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

