package main

import (
	"html/template"
	"log"
	"net/http"
)

// Define the HTML template at the package level for efficiency.
// html/template automatically escapes the keyword to prevent XSS attacks.
var searchTemplate = template.Must(template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`))

// HandleProductSearch processes product search requests.
// It extracts the keyword, handles analytics (logging), and renders the results safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search keyword for internal tracking
	if keyword != "" {
		log.Printf("Analytics: Product search performed with keyword: %s", keyword)
	}

	// 3. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Execute the template. 
	// The {{.}} pipeline in the template will be replaced by the keyword.
	// html/template ensures that if a user submits <script>alert(1)</script>, 
	// it is rendered as literal text rather than executable code.
	err := searchTemplate.Execute(w, keyword)
	if err != nil {
		// If an error occurs during execution, log it for debugging.
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

