	"time"
)

// HandleProductSearch processes search requests and displays results.
// It extracts the 'keyword' parameter, escapes it for security, and returns an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the response header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search event
	// In a real-world scenario, this might involve sending data to a database or an external API.
	log.Printf("[Analytics] Search performed - Keyword: %q, RemoteAddr: %s, Timestamp: %s", 
		keyword, r.RemoteAddr, time.Now().Format(time.RFC3339))

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// Using fmt.Fprintf to write directly to the ResponseWriter
	fmt.Fprintf(w, "<!DOCTYPE html>\n")
	fmt.Fprintf(w, "<html lang=\"en\">\n")
	fmt.Fprintf(w, "<head>\n")
	fmt.Fprintf(w, "    <meta charset=\"UTF-8\">\n")
	fmt.Fprintf(w, "    <title>Product Search Results</title>\n")
	fmt.Fprintf(w, "</head>\n")
	fmt.Fprintf(w, "<body>\n")
	fmt.Fprintf(w, "    <h2>Search Results: %s</h2>\n", escapedKeyword)

	// Placeholder for search result items
	if keyword == "" {
		fmt.Fprintf(w, "    <p>Please enter a keyword to search for products.</p>\n")
	} else {
		fmt.Fprintf(w, "    <p>Showing results for products matching your criteria.</p>\n")
	}

	fmt.Fprintf(w, "</body>\n")
	fmt.Fprintf(w, "</html>")
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Define server parameters
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)

	// Start the server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

