// HandleProductSearch processes product search requests and simulates analytics logging.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search event with timestamp and keyword
	// In a real-world scenario, this might be sent to a database or an external analytics API.
	log.Printf("[%s] Analytics: User searched for keyword: %q", time.Now().Format(time.RFC3339), keyword)

	// Escape the keyword to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: [%s]</h2>
    <!-- Search results logic would go here -->
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	fmt.Printf("Server starting on http://localhost%s/search?keyword=golang\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal(err)
	}
}

